using ModelContextProtocol.Server;
using System.ComponentModel;

/// <summary>
/// The tools are exposed to the AI model. The AI model can call these tools to perform actions.
/// </summary>
[McpServerToolType]
public static class RandomNumberTools
{
    /// <summary>
    /// This tool generates a random number. The AI model can call this tool to generate a random number within a specified range.
    /// </summary>
    [McpServerTool, Description("Generate a random number within a specified range.")]
    public static int GenerateRandomNumber(
        [Description("The minimum value (inclusive) for the random number.")] int min,
        [Description("The maximum value (exclusive) for the random number.")] int max) =>
        Random.Shared.Next(min, max);

